{
	org_validation_headers = Map();
	org_validation_headers.put("Authorization",access_token);
	org_validation_headers.put("Content-Type","application/json");
	org_validation_url = system_api_url + "api/v1.0/taxpayer/validate/" + organization_tin + "?idType=" + organization_registration_number_scheme + "&idValue=" + organization_registration_number;
	try 
	{
		org_validation_response = invokeurl
		[
			url :org_validation_url
			type :GET
			headers:org_validation_headers
		];
		if(org_validation_response != "")
		{
			// If org_validation_response is Empty, it means 200 success. 
			error_messages.add("Missing or invalid TIN and Registration Number. Please enter the correct details to proceed.");
		}
	}   catch (e)
	{
		error_messages.add("Failed to validate organization with LHDN: " + e.toString());
	}
